using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace WeatherMcpServer.Tools;

/// <summary>
/// MCP tools that wrap the Open-Meteo weather REST API.
/// Uses constructor injection — the DI container provides HttpClient automatically.
/// </summary>
[McpServerToolType]
public class WeatherTools(HttpClient httpClient, ILogger<WeatherTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get the current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location (e.g. 47.6062)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3321)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

        var url = $"https://api.open-meteo.com/v1/forecast"
            + $"?latitude={latitude}&longitude={longitude}"
            + "&current=temperature_2m,wind_speed_10m,relative_humidity_2m";

        var response = await httpClient.GetStringAsync(url, cancellationToken);

        using var doc = JsonDocument.Parse(response);
        var current = doc.RootElement.GetProperty("current");

        var result = new
        {
            temperature_c = current.GetProperty("temperature_2m").GetDouble(),
            wind_speed_kmh = current.GetProperty("wind_speed_10m").GetDouble(),
            humidity_pct = current.GetProperty("relative_humidity_2m").GetDouble()
        };

        return JsonSerializer.Serialize(result, JsonOptions);
    }

    [McpServerTool, Description("Get a 7-day daily temperature forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast"
            + $"?latitude={latitude}&longitude={longitude}"
            + "&daily=temperature_2m_max,temperature_2m_min&forecast_days=7";

        var response = await httpClient.GetStringAsync(url, cancellationToken);

        using var doc = JsonDocument.Parse(response);
        var daily = doc.RootElement.GetProperty("daily");

        var dates = daily.GetProperty("time").EnumerateArray().Select(e => e.GetString()).ToList();
        var highs = daily.GetProperty("temperature_2m_max").EnumerateArray().Select(e => e.GetDouble()).ToList();
        var lows  = daily.GetProperty("temperature_2m_min").EnumerateArray().Select(e => e.GetDouble()).ToList();

        var forecast = dates.Select((d, i) => new { date = d, high_c = highs[i], low_c = lows[i] });

        return JsonSerializer.Serialize(forecast, JsonOptions);
    }
}

